"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"(позже можно добавить и другие части: "},{"type":"text","marks":[{"type":"code"}],"text":"@ngrx/effects"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"@ngrx/store-devtools"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"@ngrx/entity"},{"type":"text","text":" и т.д.)"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"2. "},{"type":"text","marks":[{"type":"bold"}],"text":"Создать начальное состояние и reducer"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Пример: "},{"type":"text","marks":[{"type":"code"}],"text":"counter.reducer.ts"}]},{"type":"codeBlock","attrs":{"language":"ts"},"content":[{"type":"text","text":"import { createReducer, on } from '@ngrx/store';
import { increment, decrement, reset } from './counter.actions';

export const initialState = 0;

export const counterReducer = createReducer(
  initialState,
  on(increment, state => state + 1),
  on(decrement, state => state - 1),
  on(reset, _ => 0)
);
"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"3. "},{"type":"text","marks":[{"type":"bold"}],"text":"Создать actions"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Пример: "},{"type":"text","marks":[{"type":"code"}],"text":"counter.actions.ts"}]},{"type":"codeBlock","attrs":{"language":"ts"},"content":[{"type":"text","text":"import { createAction } from '@ngrx/store';

