export class AppModule {}
"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"5. "},{"type":"text","marks":[{"type":"bold"}],"text":"Использовать Store в компоненте"}]},{"type":"codeBlock","attrs":{"language":"ts"},"content":[{"type":"text","text":"import { Component } from '@angular/core';
import { Store } from '@ngrx/store';
import { increment, decrement, reset } from './counter.actions';

@Component({
  selector: 'app-counter',
  template: `
    <button (click)="decrement()">–</button>
    {{ count$ | async }}
    <button (click)="increment()">+</button>
    <button (click)="reset()">Reset</button>
  `
})
export class CounterComponent {
  count$ = this.store.select(state => state.count); // 👈 получаем значение

  constructor(private store: Store<{ count: number }>) {}

  increment() {
    this.store.dispatch(increment());
  }

  decrement() {
    this.store.dispatch(decrement());
  }

  reset() {
    this.store.dispatch(reset());
  }
