export class CounterState {
  @Action(Increment)
  increment(ctx: StateContext<number>) {
    const state = ctx.getState();
    ctx.setState(state + 1);
  }

  @Action(Decrement)
  decrement(ctx: StateContext<number>) {
    const state = ctx.getState();
    ctx.setState(state - 1);
  }
}
